from typing import List

def house_robber_ii(nums: List[int]) -> int:
    if len(nums) == 1:
        return nums[0]

    def rob_linear(houses: List[int]) -> int:
        prev2, prev1 = 0, 0
        for h in houses:
            prev2, prev1 = prev1, max(prev1, prev2 + h)
        return prev1

    # Either exclude the first house or the last house
    return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))

from typing import List

def house_robber_ii(nums: List[int]) -> int:
    if len(nums) == 1:
        return nums[0]
    if len(nums) == 2:
        return max(nums)

    def rob_linear(houses: List[int]) -> int:
        n = len(houses)
        if n == 0:
            return 0
        if n == 1:
            return houses[0]
        dp = [0] * n
        dp[0] = houses[0]
        dp[1] = max(houses[0], houses[1])
        for i in range(2, n):
            dp[i] = max(dp[i - 1], dp[i - 2] + houses[i])
        return dp[-1]

    return max(rob_linear(nums[:-1]), rob_linear(nums[1:]))

function houseRobberII(nums) {
    if (nums.length === 1) return nums[0];
    function rob(arr) {
        let a = 0, b = 0;
        for (const n of arr) { [a, b] = [b, Math.max(b, a + n)]; }
        return b;
    }
    return Math.max(rob(nums.slice(0, nums.length - 1)), rob(nums.slice(1)));
}
